public static int getLCP(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
    int lcp = 0;
    while (lcp < minLen && a.charAt(lcp) == b.charAt(lcp)) {
        lcp++;
    }
    return lcp;
}

