            new_pair = commonPrefixLength(words[i - 1], words[i + 1]);
        }
        answer[i] = Math.max(max_original, new_pair);
    }
    return answer;
}

private static int commonPrefixLength(String a, String b) {
    int minLen = Math.min(a.length(), b.length());
